<?php namespace App\Models; use Illuminate\Database\Eloquent\Factories\HasFactory;use Illuminate\Foundation\Auth\User as Authenticatable;use Illuminate\Notifications\Notifiable;use Spatie\Permission\Traits\HasRoles;use Illuminate\Database\Eloquent\Relations\HasMany;
class User extends Authenticatable{use HasFactory,Notifiable,HasRoles; protected $fillable=['name','email','password','phone','avatar','status']; protected $hidden=['password','remember_token']; protected function casts():array{return ['email_verified_at'=>'datetime','password'=>'hashed'];} public function workOrders():HasMany{return $this->hasMany(WorkOrder::class,'technician_id');}}
